from abc import ABC, abstractmethod

class Target(ABC):
    """The interface that the client expects."""

    @abstractmethod
    def request(self) -> str:
        pass

class Adaptee:
    """Contains useful behavior but has an incompatible interface."""

    def specific_request(self) -> str:
        return ".eetpadA eht fo roivaheb laicepS"

class Adapter(Target):
    """Makes Adaptee's interface compatible with Target."""

    def __init__(self, adaptee: Adaptee):
        self._adaptee = adaptee

    def request(self) -> str:
        return f"Adapter: (TRANSLATED) {self._adaptee.specific_request()[::-1]}"

# Usage
def client_code(target: Target) -> None:
    print(target.request())

# Adaptee can be used through the Adapter
adaptee = Adaptee()
adapter = Adapter(adaptee)
client_code(adapter)

